188	    if (c == 33) { /* ! */
189	        if (lex_peek() == 61) {
190	            lex_advance();
191	            lex_set(TOK_NE, "!=");
192	            return TOK_NE;
193	        }
194	        lex_set(TOK_TILDE, "!");
195	        return TOK_TILDE;
196	    }
197	    if (c == 60) { /* < */
198	        if (lex_peek() == 61) {
199	            lex_advance();
200	            lex_set(TOK_LE, "<=");
201	            return TOK_LE;
202	        }
203	        if (lex_peek() == 60) {
204	            lex_advance();
205	            lex_set(TOK_SHL, "<<");
206	            return TOK_SHL;
207	        }
208	        lex_set(TOK_LT, "<");
209	        return TOK_LT;
210	    }
211	    if (c == 62) { /* > */
