/* token.h -- Token types and keyword table for PL/SW lexer */

#ifndef TOKEN_H
#define TOKEN_H

#include "str.h"

/* Token type codes */
#define TOK_DCL       1
#define TOK_DECLARE   2
#define TOK_PROC      3
#define TOK_IF        4
#define TOK_THEN      5
#define TOK_ELSE      6
#define TOK_DO        7
#define TOK_WHILE     8
#define TOK_END       9
#define TOK_CALL      10
#define TOK_RETURN    11
#define TOK_ASM       12
#define TOK_STATIC    13
#define TOK_AUTO      14
#define TOK_EXTERNAL  15
#define TOK_INT       16
#define TOK_BYTE      17
#define TOK_CHAR      18
#define TOK_PTR       19
#define TOK_WORD      20
#define TOK_BIT       21
#define TOK_OPTIONS   22
#define TOK_RETURNS   23
#define TOK_TO        24
#define TOK_ADDR      25
#define TOK_BASED     26
#define TOK_NAKED     27

#define TOK_IDENT     40
#define TOK_NUM       41
#define TOK_STRING    42

#define TOK_PLUS      50
#define TOK_MINUS     51
#define TOK_STAR      52
#define TOK_SLASH     53
#define TOK_AMP       54
#define TOK_PIPE      55
#define TOK_CARET     56
#define TOK_TILDE     57
#define TOK_EQ        58
#define TOK_NE        59
#define TOK_LT        60
#define TOK_GT        61
#define TOK_LE        62
#define TOK_GE        63
#define TOK_SHL       64
#define TOK_SHR       65
#define TOK_ARROW     66

#define TOK_LPAREN    70
#define TOK_RPAREN    71
#define TOK_COMMA     72
#define TOK_SEMI      73
#define TOK_DOT       74
#define TOK_ASSIGN    75
#define TOK_QUESTION  76
#define TOK_PERCENT   77
#define TOK_COLON     78

#define TOK_EOF       99

/* Token structure */
#define TOK_TEXT_MAX  64

struct token {
    int type;
    int ival;
    char text[TOK_TEXT_MAX];
};

/* Keyword table -- parallel arrays (avoids tc24r struct member confusion) */
#define KW_COUNT 27

char *kw_names[KW_COUNT];
int   kw_types[KW_COUNT];

void kw_init(void) {
    kw_names[0]  = "DCL";       kw_types[0]  = TOK_DCL;
    kw_names[1]  = "DECLARE";   kw_types[1]  = TOK_DECLARE;
    kw_names[2]  = "PROC";      kw_types[2]  = TOK_PROC;
    kw_names[3]  = "IF";        kw_types[3]  = TOK_IF;
    kw_names[4]  = "THEN";      kw_types[4]  = TOK_THEN;
    kw_names[5]  = "ELSE";      kw_types[5]  = TOK_ELSE;
